import React, { useEffect, useState } from 'react';
import { View, Text, Button, TextInput, AsyncStorage } from 'react-native';
import ReactNativeBiometrics from 'react-native-biometrics';

const App = () => {
  const [authenticated, setAuthenticated] = useState(false);
  const [password, setPassword] = useState('');
  const [storedPassword, setStoredPassword] = useState('');

  useEffect(() => {
    checkAuthentication();
  }, []);

  const checkAuthentication = async () => {
    const authFlag = await AsyncStorage.getItem('authenticated');
    if (authFlag === 'true') {
      setAuthenticated(true);
    } else {
      handleBiometricAuth();
    }
  };

  const handleBiometricAuth = () => {
    ReactNativeBiometrics.isSensorAvailable()
      .then(resultObject => {
        const { available, biometryType } = resultObject;
        if (available && (biometryType === ReactNativeBiometrics.TouchID || biometryType === ReactNativeBiometrics.FaceID)) {
          ReactNativeBiometrics.simplePrompt({ promptMessage: 'Confirm your identity' })
            .then(resultObject => {
              const { success } = resultObject;
              if (success) {
                AsyncStorage.setItem('authenticated', 'true');
                setAuthenticated(true);
              }
            })
            .catch(() => {
              console.log('Biometrics failed');
            });
        } else {
          console.log('Biometrics not supported');
        }
      });
  };

  const handlePasswordAuth = async () => {
    const storedPass = await AsyncStorage.getItem('password');
    if (password === storedPass) {
      AsyncStorage.setItem('authenticated', 'true');
      setAuthenticated(true);
    } else {
      console.log('Incorrect password');
    }
  };

  const savePassword = async () => {
    await AsyncStorage.setItem('password', password);
    setStoredPassword(password);
  };

  if (authenticated) {
    return (
      <View>
        <Text>Welcome, you are authenticated!</Text>
      </View>
    );
  }

  return (
    <View>
      <Text>Login Screen</Text>
      <TextInput
        placeholder="Enter Password"
        secureTextEntry
        value={password}
        onChangeText={setPassword}
      />
      <Button title="Login with Password" onPress={handlePasswordAuth} />
      <Button title="Save Password" onPress={savePassword} />
    </View>
  );
};

export default App;